'use client';

import { createContext, useContext, useEffect, useMemo, useState, ReactNode } from 'react';
import { useRouter } from 'next/navigation';
import { authService, LoginRequest, User } from '@/lib/api/auth';

interface AuthContextType {
  user: User | null;
  loading: boolean;
  isAuthenticated: boolean;
  login: (credentials: LoginRequest) => Promise<void>;
  logout: () => Promise<void>;
  refresh: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

function redirectByRole(role?: string) {
  switch (role) {
    case 'manager_hr':
      return '/dashboard/manager-hr';
    case 'manager_departemen':
      return '/dashboard/manager-dept';
    case 'admin_departemen':
      return '/dashboard/admin-dept';
    case 'staf':
      return '/dashboard/staff';
    default:
      return '/dashboard';
  }
}

export function AuthProvider({ children }: { children: ReactNode }) {
  const router = useRouter();

  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  const refresh = async () => {
    // Versi localStorage-based: cukup baca dari authService
    setLoading(true);
    try {
      const token = authService.getAccessToken();
      const storedUser = authService.getUser();

      if (token && storedUser) setUser(storedUser);
      else setUser(null);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    // ✅ hanya sekali, jangan redirect di sini
    refresh();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const login = async (credentials: LoginRequest) => {
    setLoading(true);
    try {
      const res = await authService.login(credentials);

      // authService.login() Anda sudah simpan token+user ke localStorage + cookie
      setUser(res.user);

      router.replace(redirectByRole(res.user?.role));
    } finally {
      setLoading(false);
    }
  };

  const logout = async () => {
    setLoading(true);
    try {
      await authService.logout();
    } finally {
      setUser(null);
      setLoading(false);
      router.replace('/login');
    }
  };

  const value = useMemo<AuthContextType>(
    () => ({
      user,
      loading,
      isAuthenticated: !!user && authService.isAuthenticated(),
      login,
      logout,
      refresh,
    }),
    [user, loading]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within an AuthProvider');
  return ctx;
}